package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreEmptyLines() throws Exception {
        CSVFormat original = CSVFormat.DEFAULT;
        CSVFormat modified = original.withIgnoreEmptyLines();

        // The method withIgnoreEmptyLines() should set ignoreEmptyLines to true
        assertNotNull(modified);

        // Use reflection to access the private field 'ignoreEmptyLines'
        boolean modifiedIgnoreEmptyLines = (boolean) CSVFormat.class.getDeclaredField("ignoreEmptyLines").get(modified);
        boolean originalIgnoreEmptyLines = (boolean) CSVFormat.class.getDeclaredField("ignoreEmptyLines").get(original);

        assertTrue(modifiedIgnoreEmptyLines);

        // The original instance should remain unchanged (immutable pattern)
        assertFalse(originalIgnoreEmptyLines);

        // The modified instance should be a different object
        assertNotSame(original, modified);
    }
}
